<div class="language-java ext-java line-numbers-mode"><pre v-pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MainActivity</span> <span class="token keyword">extends</span> <span class="token class-name">AppCompatActivity</span> <span class="token keyword">implements</span> <span class="token class-name">View<span class="token punctuation">.</span>OnClickListener</span> <span class="token punctuation">{</span>
    <span class="token class-name">MyDatabaseHelper</span> dbHelper<span class="token punctuation">;</span>
    <span class="token class-name">Button</span> addData<span class="token punctuation">,</span>deleteData<span class="token punctuation">,</span>updateData<span class="token punctuation">,</span>queryData<span class="token punctuation">;</span>
    <span class="token annotation punctuation">@Override</span>
